import React from 'react';
import { Link } from 'react-router-dom';
import './BookCard.css';

const CATEGORY_COLORS = {
  Fiction:     '#c9a84c',
  'Non-Fiction':'#4caf82',
  Science:     '#5b8dee',
  History:     '#c47c5a',
  Technology:  '#9b72cf',
  Romance:     '#d4709a',
  Mystery:     '#7a9e9f',
};

export default function BookCard({ book, onEdit, onDelete, isAdmin }) {
  const color = CATEGORY_COLORS[book.category] || '#c9a84c';
  const initial = (book.title || 'B')[0].toUpperCase();

  return (
    <div className="book-card fade-up">
      {/* Cover */}
      <div className="book-cover" style={{ '--accent': color }}>
        <div className="book-spine" style={{ background: color }} />
        <div className="book-initial">{initial}</div>
        <div className="book-category-tag">{book.category || 'General'}</div>
        {book.stock === 0 && (
          <div className="book-out-of-stock">Out of Stock</div>
        )}
      </div>

      {/* Info */}
      <div className="book-info">
        <h3 className="book-title">{book.title}</h3>
        <p className="book-author">by {book.author}</p>

        <div className="book-meta">
          <span className="book-price">₹{book.price?.toFixed(2)}</span>
          <span className="book-stock" style={{ color: book.stock > 0 ? 'var(--green)' : 'var(--red)' }}>
            {book.stock > 0 ? `${book.stock} in stock` : 'Out of stock'}
          </span>
        </div>

        {/* Actions */}
        <div className="book-actions">
          <Link to={`/books/${book.id}`} className="btn btn-outline btn-xs">View</Link>
          {isAdmin && (
            <>
              <button className="btn btn-ghost btn-xs" onClick={() => onEdit(book)}>Edit</button>
              <button className="btn btn-danger btn-xs" onClick={() => onDelete(book.id)}>Delete</button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
